    private static boolean sieveInitialized = false;

    private static void initializeSieve() {
        if (sieveInitialized) return;

        // Initialize all numbers as potentially prime
        Arrays.fill(isPrime, true);
        isPrime[0] = false; // 0 is not prime
        isPrime[1] = false; // 1 is not prime

        for (int p = 2; p * p <= MAX_SIEVE; p++) {
            if (isPrime[p]) {
                // Mark all multiples of p as not prime
                for (int i = p * p; i <= MAX_SIEVE; i += p)
                    isPrime[i] = false;
            }
        }
        sieveInitialized = true;
    }

    /**
     * Finds the smallest prime number P >= N.
     * Assumes N <= MAX_SIEVE.
     */
    private static long findNextPrime(long N) {
        if (N > MAX_SIEVE) {
            // This case should ideally not happen given the constraints and buffer size, 
            // but robust code might require a slower primality test here.
            // For contest setting, we rely on the buffer being large enough.
            // Since N <= 10^5 and MAX_SIEVE = 100500, this is safe.
        }
        long k = N;
        while (k <= MAX_SIEVE && !isPrime[(int)k]) {
            k++;
        }
        return k;
    }

